sql:
SELECT AVG(market_capitalization) AS Average_Market_Capitalization
FROM securities
WHERE sector = 'Technology';

SELECT DISTINCT s.symbol, s.name
FROM securities s
JOIN market_data md ON s.symbol = md.symbol;

SELECT symbol, SUM(different_entries) AS total_different_entries
FROM entries
GROUP BY symbol;

SELECT name
FROM securities
WHERE market_capitalization = (SELECT MAX(market_capitalization) FROM securities);

SELECT headline 
FROM news 
WHERE symbol = 'AAPL';
